    scores = {'Sports': 0, 'Business': 0, 'Sci/Tech': 0, 'World': 0}
    
    # Sports (Keep same)
    sports_keywords = ['sport', 'football', 'soccer', 'basketball', 'baseball', 'tennis', 'golf', 'hockey', 'league', 'cup', 'game', 'match', 'score', 'team', 'player', 'coach', 'nba', 'nfl', 'mlb', 'nhl', 'olympic', 'championship', 'tournament', 'medal', 'athlete', 'stadium', 'club', 'united', 'arsenal', 'chelsea', 'liverpool', 'real madrid', 'barcelona', 'yankees', 'red sox', 'lakers', 'bulls', 'knicks', 'rangers', 'cup', 'won', 'lost', 'victory', 'defeat']
