    business_keywords = ['business', 'company', 'corp', 'inc', 'stock', 'market', 'share', 'profit', 'loss', 'revenue', 'earnings', 'quarter', 'deal', 'merger', 'acquisition', 'buyout', 'ipo', 'ceo', 'cfo', 'bank', 'finance', 'economy', 'trade', 'dollar', 'euro', 'oil', 'price', 'invest', 'fund', 'wall street', 'nasdaq', 'dow jones', 'fed', 'interest rate', 'inflation', 'sales', 'retail', 'audit', 'bankruptcy']
