        'europe', 'ukraine', 'russia', 'france', 'paris', 'germany', 'berlin', 'uk', 'britain', 'london', 'greece', 'athens', 'italy', 'rome', 'spain', 'madrid', 'turkey', 'migrant',
        'asia', 'china', 'beijing', 'japan', 'tokyo', 'korea', 'india', 'delhi', 'pakistan', 'afghanistan', 'kabul', 'iraq', 'baghdad', 'iran', 'tehran', 'syria', 'damascus', 'israel', 'jerusalem', 'palestine', 'gaza', 'isis', 'islamic state', 'yemen', 'saudi', 'thailand', 'indonesia',
        'africa', 'egypt', 'cairo', 'libya', 'tunisia', 'nigeria', 'boko haram', 'kenya', 'somalia', 'sudan', 'darfur', 'congo', 'zimbabwe', 'south africa',
